/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently focused on email settings — designed to extend
 * to additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * How often a user wants to receive email notifications.
 * - instant: deliver immediately
 * - daily_digest: batch into a daily summary
 * - weekly_digest: batch into a weekly summary
 *
 * Note: only 'instant' is currently implemented. Digest modes
 * are modeled for forward-compatibility but not yet delivered.
 */
export type EmailFrequency = 'instant' | 'daily_digest' | 'weekly_digest';

/**
 * Per-category email subscription setting.
 */
export interface CategoryPreference {
  /** The notification category. */
  category: NotificationType;
  /** Whether the user wants to receive this category. */
  enabled: boolean;
}

/**
 * Full notification preferences for a single user.
 */
export interface UserPreferences {
  /** Unique preferences record ID. */
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** Master switch for all email notifications. */
  emailEnabled: boolean;
  /** How often to deliver email notifications. */
  emailFrequency: EmailFrequency;
  /** Per-category opt-in/out settings. */
  categoryPreferences: CategoryPreference[];
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating or fully replacing preferences.
 */
export interface UpdatePreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  categoryPreferences?: CategoryPreference[];
}

/**
 * All known notification categories — used to build defaults.
 */
export const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_update',
  'system_alert',
];

/**
 * Build the default preferences (everything enabled, instant delivery).
 */
export function buildDefaultPreferences(userId: string, id: string): UserPreferences {
  const now = new Date();
  return {
    id,
    userId,
    emailEnabled: true,
    emailFrequency: 'instant',
    categoryPreferences: ALL_NOTIFICATION_TYPES.map((category) => ({
      category,
      enabled: true,
    })),
    createdAt: now,
    updatedAt: now,
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Each user has at most one preferences record.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, CategoryPreference } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      emailEnabled: record['emailEnabled'] as boolean,
      emailFrequency: record['emailFrequency'] as UserPreferences['emailFrequency'],
      categoryPreferences: JSON.parse(record['categoryPreferences'] as string) as CategoryPreference[],
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.emailEnabled,
      emailFrequency: entity.emailFrequency,
      categoryPreferences: JSON.stringify(entity.categoryPreferences),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for managing user notification preferences.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 *
 * Provides:
 * - CRUD for user preferences
 * - shouldSendNotification() check used by NotificationService
 * - Default preferences for users who haven't configured any
 */

import type { NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import { buildDefaultPreferences } from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns default preferences if none exist.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    // Return transient defaults (not persisted until user explicitly updates)
    return buildDefaultPreferences(userId, generatePreferencesId());
  }

  /**
   * Update preferences for a user. Creates the record if it doesn't exist yet.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    this.logger.info(`Updating preferences for user ${userId}`);

    const existing = this.repository.findByUserId(userId);

    if (existing) {
      const updated: UserPreferences = {
        ...existing,
        ...(input.emailEnabled !== undefined && { emailEnabled: input.emailEnabled }),
        ...(input.emailFrequency !== undefined && { emailFrequency: input.emailFrequency }),
        ...(input.categoryPreferences !== undefined && { categoryPreferences: input.categoryPreferences }),
        updatedAt: new Date(),
      };
      return this.repository.update(existing.id, updated);
    }

    // Create new preferences based on defaults, then apply input
    const id = generatePreferencesId();
    const defaults = buildDefaultPreferences(userId, id);
    const newPrefs: UserPreferences = {
      ...defaults,
      ...(input.emailEnabled !== undefined && { emailEnabled: input.emailEnabled }),
      ...(input.emailFrequency !== undefined && { emailFrequency: input.emailFrequency }),
      ...(input.categoryPreferences !== undefined && { categoryPreferences: input.categoryPreferences }),
    };
    return this.repository.save(newPrefs);
  }

  /**
   * Check whether a notification should be sent to a user based on their preferences.
   *
   * Returns true if:
   * 1. Email is globally enabled for the user
   * 2. The specific notification category is enabled
   *
   * Users without explicit preferences get defaults (all enabled).
   */
  shouldSendNotification(userId: string, type: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.emailEnabled) {
      this.logger.info(`Email disabled for user ${userId}, suppressing ${type}`);
      return false;
    }

    const catPref = prefs.categoryPreferences.find((cp) => cp.category === type);
    // If no category preference found, allow by default
    if (catPref && !catPref.enabled) {
      this.logger.info(`Category ${type} disabled for user ${userId}, suppressing`);
      return false;
    }

    return true;
  }

  /**
   * Reset preferences for a user back to defaults.
   */
  resetPreferences(userId: string): UserPreferences {
    this.logger.info(`Resetting preferences for user ${userId}`);

    const existing = this.repository.findByUserId(userId);
    if (existing) {
      this.repository.delete(existing.id);
    }

    return this.getPreferences(userId);
  }
}

