+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
+import {
+  PreferencesService,
+  resetPreferencesIdCounter,
+} from '../../src/services/preferences.service.js';
+import type { NotificationType } from '../../src/models/notification.js';
+import { ALL_NOTIFICATION_TYPES } from '../../src/models/user-preferences.js';
+import type { CategoryPreference } from '../../src/models/user-preferences.js';
+
+describe('PreferencesService', () => {
+  let db: Database;
+  let repository: PreferencesRepository;
+  let service: PreferencesService;
+
+  beforeEach(() => {
+    db = new Database();
+    repository = new PreferencesRepository(db);
+    service = new PreferencesService(repository);
+    resetPreferencesIdCounter();
+  });
+
+  describe('getPreferences', () => {
+    it('should return default preferences for a user with no saved preferences', () => {
+      const prefs = service.getPreferences('user-1');
+
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.emailEnabled).toBe(true);
+      expect(prefs.emailFrequency).toBe('instant');
+      expect(prefs.categoryPreferences).toHaveLength(ALL_NOTIFICATION_TYPES.length);
+      for (const cp of prefs.categoryPreferences) {
+        expect(cp.enabled).toBe(true);
+      }
+    });
+
+    it('should return saved preferences when they exist', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.emailEnabled).toBe(false);
+    });
+
+    it('should return independent defaults for different users', () => {
+      const prefs1 = service.getPreferences('user-1');
+      const prefs2 = service.getPreferences('user-2');
+
+      expect(prefs1.userId).toBe('user-1');
+      expect(prefs2.userId).toBe('user-2');
+      expect(prefs1.id).not.toBe(prefs2.id);
+    });
+  });
+
+  describe('updatePreferences', () => {
+    it('should create preferences on first update', () => {
+      const prefs = service.updatePreferences('user-1', { emailEnabled: false });
+
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.emailEnabled).toBe(false);
+      // Other defaults should be preserved
+      expect(prefs.emailFrequency).toBe('instant');
+    });
+
+    it('should update email frequency', () => {
+      const prefs = service.updatePreferences('user-1', { emailFrequency: 'daily_digest' });
+
+      expect(prefs.emailFrequency).toBe('daily_digest');
+      expect(prefs.emailEnabled).toBe(true);
+    });
+
+    it('should update category preferences', () => {
+      const categories: CategoryPreference[] = [
+        { category: 'order_confirmation', enabled: true },
+        { category: 'order_status_update', enabled: true },
+        { category: 'welcome', enabled: false },
+        { category: 'account_update', enabled: true },
+        { category: 'system_alert', enabled: false },
+      ];
+
+      const prefs = service.updatePreferences('user-1', { categoryPreferences: categories });
+
+      const welcome = prefs.categoryPreferences.find((cp) => cp.category === 'welcome');
+      expect(welcome?.enabled).toBe(false);
+
+      const systemAlert = prefs.categoryPreferences.find((cp) => cp.category === 'system_alert');
+      expect(systemAlert?.enabled).toBe(false);
+    });
+
+    it('should update existing preferences without resetting other fields', () => {
+      service.updatePreferences('user-1', { emailFrequency: 'weekly_digest' });
+      const prefs = service.updatePreferences('user-1', { emailEnabled: false });
+
+      expect(prefs.emailEnabled).toBe(false);
+      expect(prefs.emailFrequency).toBe('weekly_digest');
+    });
+
+    it('should handle multiple updates to the same user', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      service.updatePreferences('user-1', { emailEnabled: true });
+
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.emailEnabled).toBe(true);
+    });
+  });
+
+  describe('shouldSendNotification', () => {
+    it('should allow notification when all preferences are default', () => {
+      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
+    });
+
+    it('should block notification when email is globally disabled', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+
+      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
+      expect(service.shouldSendNotification('user-1', 'system_alert')).toBe(false);
+    });
+
+    it('should block notification for a disabled category', () => {
+      const categories: CategoryPreference[] = ALL_NOTIFICATION_TYPES.map((cat) => ({
+        category: cat,
+        enabled: cat !== 'welcome',
+      }));
+
+      service.updatePreferences('user-1', { categoryPreferences: categories });
+
+      expect(service.shouldSendNotification('user-1', 'welcome')).toBe(false);
+      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
+    });
+
+    it('should allow notification when email enabled and category enabled', () => {
+      service.updatePreferences('user-1', { emailEnabled: true });
+
+      expect(service.shouldSendNotification('user-1', 'order_status_update')).toBe(true);
+    });
+
+    it('should allow notification for unknown categories by default', () => {
+      // If a category pref is missing for a type, default to allowed
+      service.updatePreferences('user-1', { categoryPreferences: [] });
+
+      expect(service.shouldSendNotification('user-1', 'system_alert')).toBe(true);
+    });
+  });
+
+  describe('resetPreferences', () => {
+    it('should reset to defaults after customization', () => {
+      service.updatePreferences('user-1', {
+        emailEnabled: false,
+        emailFrequency: 'weekly_digest',
+      });
+
+      const prefs = service.resetPreferences('user-1');
+
+      expect(prefs.emailEnabled).toBe(true);
+      expect(prefs.emailFrequency).toBe('instant');
+    });
+
+    it('should work for user with no saved preferences', () => {
+      const prefs = service.resetPreferences('user-1');
+
+      expect(prefs.emailEnabled).toBe(true);
+      expect(prefs.emailFrequency).toBe('instant');
+    });
+  });
+});
